1	<script lang="ts">
2		import type { PageData } from './$types'
3		import { page } from '$app/stores'
4		import { goto } from '$app/navigation'
5		import { createClient } from '$lib/gql/client'
6		import { PROJECT_RUNS_QUERY, PAGE_SIZE } from './+page'
7		import type { RunEdge, RunNode, RunConnection, PageInfo } from './+page'
8		import { RunRowDetail } from '$lib/runDetail'
9		import ConfirmDialog from '$lib/components/ConfirmDialog.svelte'
10		import { RUN_REQUEUE_MUTATION, WORKER_DISPATCH_MUTATION } from '$lib/gql/feat008'
11	
12		let { data }: { data: PageData } = $props()
13	
14		let appendedEdges = $state<RunEdge[]>([])
15		let appendedPageInfo = $state<PageInfo | null>(null)
16		let loadingMore = $state(false)
17		let harnessInput = $state(data.activeHarness ?? '')
18		let expanded = $state<Set<string>>(new Set())
19	
20		type ActionMode = 'requeue' | 'startWorker'
21		let actionDialogOpen = $state(false)
22		let actionMode = $state<ActionMode>('requeue')
23		let actionRun = $state<RunNode | null>(null)
24		let actionIdempotencyKey = $state('')
25		let actionLayerOverride = $state('')
26		let actionWorkerArgs = $state('')
27		let actionAlert = $state('')
28		let actionResultMessage = $state('')
29	
30		function newIdempotencyKey(): string {
31			if (typeof crypto !== 'undefined' && typeof crypto.randomUUID === 'function') {
32				return crypto.randomUUID()
33			}
34			return `requeue-${Date.now()}-${Math.random().toString(36).slice(2, 10)}`
35		}
36	
37		function openRequeueDialog(run: RunNode) {
38			actionMode = 'requeue'
39			actionRun = run
40			actionIdempotencyKey = newIdempotencyKey()
41			actionLayerOverride = run.layer
42			actionAlert = ''
43			actionResultMessage = ''
44			actionDialogOpen = true
45		}
46	
47		function openStartWorkerDialog(run: RunNode) {
48			actionMode = 'startWorker'
49			actionRun = run
50			actionAlert = ''
51			actionResultMessage = ''
52			// Prefill the worker args with the original drain's queueInputs JSON.
53			// Pretty-print so the operator can review/edit before dispatching.
54			if (run.queueInputs) {
55				try {
56					actionWorkerArgs = JSON.stringify(JSON.parse(run.queueInputs), null, 2)
57				} catch {
58					actionWorkerArgs = run.queueInputs
59				}
60			} else {
61				actionWorkerArgs = JSON.stringify(
62					{ source: 'runs-start-worker', sourceRunId: run.id },
63					null,
64					2
65				)
66			}
67			actionDialogOpen = true
68		}
69	
70		async function confirmAction() {
71			if (!actionRun) return
72			const client = createClient()
73			try {
74				if (actionMode === 'requeue') {
75					if (!actionIdempotencyKey.trim()) {
76						actionAlert = 'Idempotency key is required.'
77						throw new Error('missing idempotency key')
78					}
79					const layer = actionLayerOverride.trim()
80					const result = await client.request<{
81						runRequeue: { bead: { id: string }; deduplicated: boolean }
82					}>(RUN_REQUEUE_MUTATION, {
83						input: {
84							runId: actionRun.id,
85							idempotencyKey: actionIdempotencyKey,
86							layer: layer ? layer : null
87						}
88					})
89					actionResultMessage = result.runRequeue.deduplicated
90						? `Bead ${result.runRequeue.bead.id} already requeued (deduplicated).`
91						: `Bead ${result.runRequeue.bead.id} requeued.`
92				} else {
93					// startWorker: validate JSON before sending so the operator can fix it inline.
94					let argsString = actionWorkerArgs.trim()
95					if (argsString) {
96						try {
97							JSON.parse(argsString)
98						} catch (err) {
99							actionAlert = `Worker args must be valid JSON: ${errorText(err)}`
100							throw err
101						}
102					} else {
103						argsString = '{}'
104					}
105					const projectId = actionRun.projectID ?? data.projectId
106					const result = await client.request<{
107						workerDispatch: { id: string; state: string; kind: string }
108					}>(WORKER_DISPATCH_MUTATION, {
109						kind: 'execute-loop',
110						projectId,
111						args: argsString
112					})
113					actionResultMessage = `Worker ${result.workerDispatch.id} started (${result.workerDispatch.state}).`
114				}
115			} catch (err) {
116				if (!actionAlert) actionAlert = errorText(err)
117				throw err
118			}
119		}
120	
121		function errorText(err: unknown): string {
122			if (err instanceof Error) return err.message
123			if (typeof err === 'string') return err
124			return 'Unknown error.'
125		}
126	
127		function toggleExpand(runId: string) {
128			const next = new Set(expanded)
129			if (next.has(runId)) next.delete(runId)
130			else next.add(runId)
131			expanded = next
132		}
133	
134		let filterKey = $derived(`${data.activeLayer}::${data.activeStatus}::${data.activeHarness}`)
135		let prevFilterKey = $state('')
136		$effect(() => {
137			if (filterKey !== prevFilterKey) {
138				prevFilterKey = filterKey
139				appendedEdges = []
140				appendedPageInfo = null
141			}
142		})
143	
144		let edges = $derived([...data.runs.edges, ...appendedEdges])
145		let pageInfo = $derived<PageInfo>(appendedPageInfo ?? data.runs.pageInfo)
146	
147		const LAYER_OPTIONS = ['work', 'try', 'run']
148		const STATUS_OPTIONS = ['pending', 'running', 'success', 'failure', 'preserved']
149	
150		function setFilter(key: 'layer' | 'status' | 'harness', value: string | null) {
151			const params = new URLSearchParams($page.url.searchParams)
152			if (value === null || value === '') {
153				params.delete(key)
154			} else {
155				params.set(key, value)
156			}
157			const search = params.toString()
158			goto(search ? `?${search}` : $page.url.pathname, { replaceState: false })
159		}
160	
161		function toggleLayer(layer: string) {
162			setFilter('layer', data.activeLayer === layer ? null : layer)
163		}
164	
165		function toggleStatus(status: string) {
166			setFilter('status', data.activeStatus === status ? null : status)
167		}
168	
169		function applyHarness() {
170			setFilter('harness', harnessInput.trim() || null)
171		}
172	
173		async function loadMore() {
174			if (!pageInfo.hasNextPage || loadingMore) return
175			loadingMore = true
176			try {
177				const client = createClient()
178				const result = await client.request<{ runs: RunConnection }>(PROJECT_RUNS_QUERY, {
179					projectID: data.projectId,
180					first: PAGE_SIZE,
181					after: pageInfo.endCursor,
182					layer: data.activeLayer ?? undefined,
183					status: data.activeStatus ?? undefined,
184					harness: data.activeHarness ?? undefined
185				})
186				appendedEdges = [...appendedEdges, ...result.runs.edges]
187				appendedPageInfo = result.runs.pageInfo
188			} finally {
189				loadingMore = false
190			}
191		}
192	
193		function runDetailHref(runId: string): string {
194			return `/nodes/${data.nodeId}/projects/${data.projectId}/runs/${runId}`
195		}
196	
197		function beadHref(beadId: string): string {
198			return `/nodes/${data.nodeId}/projects/${data.projectId}/beads/${beadId}`
199		}
200	
201		function fmtDate(iso: string | null): string {
202			if (!iso) return '—'
203			return new Date(iso).toLocaleString()
204		}
205	
206		function fmtDuration(ms: number | null): string {
207			if (ms == null) return '—'
208			if (ms < 1000) return `${ms}ms`
209			if (ms < 60_000) return `${(ms / 1000).toFixed(1)}s`
210			const m = Math.floor(ms / 60_000)
211			const s = Math.floor((ms % 60_000) / 1000)
212			return `${m}m ${s}s`
213		}
214	
215		function layerBadgeClass(layer: string): string {
216			switch (layer) {
217				case 'work':
218					return 'badge-layer-work'
219				case 'try':
220					return 'badge-layer-try'
221				case 'run':
222					return 'badge-layer-run'
223				default:
224					return 'badge-status-neutral'
225			}
226		}
227	
228		function statusBadgeClass(status: string): string {
229			switch (status) {
230				case 'success':
231					return 'badge-status-closed'
232				case 'failure':
233					return 'badge-status-failed'
234				case 'running':
235					return 'badge-status-running'
236				case 'preserved':
237					return 'badge-status-in-progress'
238				default:
239					return 'badge-status-open'
240			}
241		}
242	
243		function chipClass(active: boolean): string {
244			return active
245				? 'rounded-sm border px-3 py-1 text-xs font-medium border-accent-lever bg-accent-lever/10 text-accent-lever dark:border-dark-accent-lever dark:bg-dark-accent-lever/20 dark:text-dark-accent-lever'
246				: 'rounded-sm border px-3 py-1 text-xs font-medium border-border-line bg-bg-elevated text-fg-ink hover:border-fg-muted hover:bg-bg-surface dark:border-dark-border-line dark:bg-dark-bg-elevated dark:text-dark-fg-ink dark:hover:bg-dark-bg-surface'
247		}
248	</script>
249	
250	<div class="space-y-4">
251		<div class="flex items-center justify-between">
252			<h1 class="text-headline-lg font-headline-lg text-fg-ink dark:text-dark-fg-ink">Runs</h1>
253			<span class="text-body-sm text-fg-muted dark:text-dark-fg-muted">
254				{edges.length} of {data.runs.totalCount}
255			</span>
256		</div>
257	
258		<!-- Layer filter chips -->
259		<div class="flex flex-wrap gap-2">
260			<span class="self-center text-xs text-fg-muted dark:text-dark-fg-muted">Layer:</span>
261			{#each LAYER_OPTIONS as layer}
262				<button class={chipClass(data.activeLayer === layer)} onclick={() => toggleLayer(layer)}>
263					{layer}
264				</button>
265			{/each}
266			{#if data.activeLayer}
267				<button
268					class="rounded-sm border border-border-line bg-bg-elevated px-3 py-1 text-xs text-fg-ink hover:bg-bg-surface dark:border-dark-border-line dark:bg-dark-bg-elevated dark:text-dark-fg-ink dark:hover:bg-dark-bg-surface"
269					onclick={() => setFilter('layer', null)}
270				>
271					clear
272				</button>
273			{/if}
274		</div>
275	
276		<!-- Status filter chips -->
277		<div class="flex flex-wrap gap-2">
278			<span class="self-center text-xs text-fg-muted dark:text-dark-fg-muted">Status:</span>
279			{#each STATUS_OPTIONS as status}
280				<button class={chipClass(data.activeStatus === status)} onclick={() => toggleStatus(status)}>
281					{status}
282				</button>
283			{/each}
284			{#if data.activeStatus}
285				<button
286					class="rounded-sm border border-border-line bg-bg-elevated px-3 py-1 text-xs text-fg-ink hover:bg-bg-surface dark:border-dark-border-line dark:bg-dark-bg-elevated dark:text-dark-fg-ink dark:hover:bg-dark-bg-surface"
287					onclick={() => setFilter('status', null)}
288				>
289					clear
290				</button>
291			{/if}
292		</div>
293	
294		<!-- Harness filter -->
295		<form
296			class="flex items-center gap-2"
297			onsubmit={(e) => {
298				e.preventDefault()
299				applyHarness()
300			}}
301		>
302			<span class="text-xs text-fg-muted dark:text-dark-fg-muted">Harness:</span>
303			<input
304				type="text"
305				bind:value={harnessInput}
306				placeholder="claude / codex / agent"
307				class="w-44 border border-border-line bg-bg-elevated px-2 py-1 font-mono-code text-mono-code text-fg-ink dark:border-dark-border-line dark:bg-dark-bg-elevated dark:text-dark-fg-ink"
308			/>
309			<button
310				type="submit"
311				class="border border-border-line bg-bg-elevated px-2 py-1 text-xs text-fg-muted hover:bg-bg-surface dark:border-dark-border-line dark:bg-dark-bg-elevated dark:text-dark-fg-muted dark:hover:bg-dark-bg-surface"
312			>
313				Apply
314			</button>
315			{#if data.activeHarness}
316				<button
317					type="button"
318					onclick={() => {
319						harnessInput = ''
320						setFilter('harness', null)
321					}}
322					class="border border-border-line bg-bg-elevated px-2 py-1 text-xs text-fg-muted hover:bg-bg-surface dark:border-dark-border-line dark:bg-dark-bg-elevated dark:text-dark-fg-muted dark:hover:bg-dark-bg-surface"
323				>
324					Clear
325				</button>
326			{/if}
327		</form>
328	
329		<div class="overflow-hidden border border-border-line dark:border-dark-border-line">
330			<table class="w-full text-sm">
331				<thead>
332					<tr class="border-b border-border-line bg-bg-surface dark:border-dark-border-line dark:bg-dark-bg-surface">
333						<th class="w-6 px-4 py-3"></th>
334						<th class="px-4 py-3 text-left font-label-caps text-label-caps uppercase tracking-wide text-fg-muted dark:text-dark-fg-muted">Layer</th>
335						<th class="px-4 py-3 text-left font-label-caps text-label-caps uppercase tracking-wide text-fg-muted dark:text-dark-fg-muted">Status</th>
336						<th class="px-4 py-3 text-left font-label-caps text-label-caps uppercase tracking-wide text-fg-muted dark:text-dark-fg-muted">Bead</th>
337						<th class="px-4 py-3 text-left font-label-caps text-label-caps uppercase tracking-wide text-fg-muted dark:text-dark-fg-muted">Harness</th>
338						<th class="px-4 py-3 text-left font-label-caps text-label-caps uppercase tracking-wide text-fg-muted dark:text-dark-fg-muted">Started</th>
339						<th class="px-4 py-3 text-right font-label-caps text-label-caps uppercase tracking-wide text-fg-muted dark:text-dark-fg-muted">Duration</th>
340						<th class="px-4 py-3 text-right font-label-caps text-label-caps uppercase tracking-wide text-fg-muted dark:text-dark-fg-muted">Actions</th>
341					</tr>
342				</thead>
343				<tbody>
344					{#each edges as edge (edge.cursor)}
345						{@const isExpanded = expanded.has(edge.node.id)}
346						<tr
347							class="cursor-pointer border-b border-border-line last:border-0 hover:bg-bg-surface dark:border-dark-border-line dark:hover:bg-dark-bg-surface {isExpanded
348								? 'bg-accent-lever/10 dark:bg-dark-accent-lever/10'
349								: ''}"
350							data-run-row={edge.node.id}
351							onclick={() => toggleExpand(edge.node.id)}
352						>
353							<td class="px-4 py-3 text-body-sm text-fg-muted dark:text-dark-fg-muted">
354								{isExpanded ? '▾' : '▸'}
355							</td>
356							<td class="px-4 py-3">
357								<span class="inline-block rounded-full px-2 py-0.5 font-label-caps text-label-caps uppercase {layerBadgeClass(edge.node.layer)}">
358									{edge.node.layer}
359								</span>
360							</td>
361							<td class="px-4 py-3">
362								<span class="inline-block border px-1.5 py-0.5 font-mono-code text-mono-code uppercase {statusBadgeClass(edge.node.status)}">
363									{edge.node.status}
364								</span>
365							</td>
366							<td class="px-4 py-3">
367								{#if edge.node.beadId}
368									<a
369										href={beadHref(edge.node.beadId)}
370										onclick={(e) => e.stopPropagation()}
371										class="font-mono-code text-mono-code text-accent-lever hover:underline dark:text-dark-accent-lever"
372									>
373										{edge.node.beadId}
374									</a>
375								{:else}
376									<span class="text-fg-muted dark:text-dark-fg-muted">—</span>
377								{/if}
378							</td>
379							<td class="px-4 py-3 font-mono-code text-mono-code text-fg-muted dark:text-dark-fg-muted">
380								{edge.node.harness ?? '—'}
381							</td>
382							<td class="px-4 py-3 font-mono-code text-mono-code text-fg-muted dark:text-dark-fg-muted">
383								{fmtDate(edge.node.startedAt)}
384							</td>
385							<td class="px-4 py-3 text-right font-mono-code text-mono-code text-fg-muted dark:text-dark-fg-muted">
386								<div class="flex items-center justify-end gap-2">
387									<span>{fmtDuration(edge.node.durationMs)}</span>
388									<a
389										href={runDetailHref(edge.node.id)}
390										onclick={(e) => e.stopPropagation()}
391										title="Open detail page"
392										class="font-mono-code text-mono-code text-accent-lever hover:underline dark:text-dark-accent-lever"
393									>
394										↗
395									</a>
396								</div>
397							</td>
398							<td class="px-4 py-3 text-right">
399								{#if edge.node.layer === 'work'}
400									<button
401										type="button"
402										data-run-action="start-worker"
403										data-run-id={edge.node.id}
404										onclick={(e) => {
405											e.stopPropagation()
406											openStartWorkerDialog(edge.node)
407										}}
408										class="rounded-sm border border-border-line bg-bg-elevated px-2 py-1 text-xs font-medium text-fg-ink hover:bg-bg-surface dark:border-dark-border-line dark:bg-dark-bg-elevated dark:text-dark-fg-ink dark:hover:bg-dark-bg-surface"
409									>
410										Start worker
411									</button>
412								{:else}
413									<button
414										type="button"
415										data-run-action="requeue"
416										data-run-id={edge.node.id}
417										onclick={(e) => {
418											e.stopPropagation()
419											openRequeueDialog(edge.node)
420										}}
421										class="rounded-sm border border-border-line bg-bg-elevated px-2 py-1 text-xs font-medium text-fg-ink hover:bg-bg-surface dark:border-dark-border-line dark:bg-dark-bg-elevated dark:text-dark-fg-ink dark:hover:bg-dark-bg-surface"
422									>
423										Re-queue
424									</button>
425								{/if}
426							</td>
427						</tr>
428						{#if isExpanded}
429							<tr class="border-b border-border-line bg-bg-surface dark:border-dark-border-line dark:bg-dark-bg-surface">
430								<td colspan="8" class="px-6 py-4">
431									<RunRowDetail
432										runId={edge.node.id}
433										layer={edge.node.layer}
434										nodeId={data.nodeId}
435										projectId={data.projectId}
436									/>
437								</td>
438							</tr>
439						{/if}
440					{/each}
441					{#if edges.length === 0}
442						<tr>
443							<td colspan="8" class="px-4 py-8 text-center text-body-sm text-fg-muted dark:text-dark-fg-muted">
444								No runs found.
445							</td>
446						</tr>
447					{/if}
448				</tbody>
449			</table>
450		</div>
451	
452		{#if actionResultMessage}
453			<div
454				role="status"
455				class="rounded-md border border-accent-fulcrum/30 bg-accent-fulcrum/10 px-4 py-2 text-sm text-fg-ink dark:border-dark-accent-fulcrum/30 dark:bg-dark-accent-fulcrum/10 dark:text-dark-fg-ink"
456				data-run-action-result
457			>
458				{actionResultMessage}
459			</div>
460		{/if}
461	
462		{#if pageInfo.hasNextPage}
463			<div class="flex justify-center">
464				<button
465					onclick={loadMore}
466					disabled={loadingMore}
467					class="rounded border border-border-line bg-bg-surface px-4 py-2 text-body-sm text-fg-muted hover:bg-bg-elevated hover:text-fg-ink disabled:opacity-50 dark:border-dark-border-line dark:bg-dark-bg-surface dark:text-dark-fg-muted dark:hover:bg-dark-bg-elevated dark:hover:text-dark-fg-ink"
468				>
469					{loadingMore ? 'Loading…' : 'Load more'}
470				</button>
471			</div>
472		{/if}
473	</div>
474	
475	<ConfirmDialog
476		bind:open={actionDialogOpen}
477		title={actionMode === 'requeue' ? 'Re-queue run' : 'Start worker from this drain'}
478		actionLabel={actionMode === 'requeue' ? 'Re-queue' : 'Start worker'}
479		onConfirm={confirmAction}
480	>
481		{#snippet summary()}
482			<span>
483				{#if actionRun}
484					{actionMode === 'requeue'
485						? `Re-queue ${actionRun.layer} run ${actionRun.id}`
486						: `Start an execute-loop worker prefilled from work run ${actionRun.id}`}
487				{/if}
488			</span>
489		{/snippet}
490	
491		{#if actionRun}
492			<div class="space-y-3">
493				{#if actionAlert}
494					<div
495						role="alert"
496						class="rounded border border-error/30 bg-error/10 px-3 py-2 text-xs text-error dark:border-dark-error/30 dark:bg-dark-error/10 dark:text-dark-error"
497						data-run-action-alert
498					>
499						{actionAlert}
500					</div>
501				{/if}
502	
503				{#if actionMode === 'requeue'}
504					<div>
505						<label class="mb-1 block font-label-caps text-label-caps uppercase text-fg-muted dark:text-dark-fg-muted" for="requeue-run-id">
506							Run ID
507						</label>
508						<input
509							id="requeue-run-id"
510							type="text"
511							readonly
512							value={actionRun.id}
513							class="w-full border border-border-line bg-bg-surface px-2 py-1 font-mono-code text-mono-code text-fg-ink dark:border-dark-border-line dark:bg-dark-bg-surface dark:text-dark-fg-ink"
514						/>
515					</div>
516					<div>
517						<label class="mb-1 block font-label-caps text-label-caps uppercase text-fg-muted dark:text-dark-fg-muted" for="requeue-layer">
518							Layer override
519						</label>
520						<select
521							id="requeue-layer"
522							bind:value={actionLayerOverride}
523							class="w-full border border-border-line bg-bg-elevated px-2 py-1 font-mono-code text-mono-code text-fg-ink dark:border-dark-border-line dark:bg-dark-bg-elevated dark:text-dark-fg-ink"
